#include <stdio.h>
#include <string.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int minCommands = 0;
        int staged = 0;
        for (int i = 0; i < N; i++) {
            char command[10], path[101];
            scanf("%s %s", command, path);
            if (strcmp(command, "unstage") == 0) {
                minCommands++;
            } else if (strcmp(command, "stage") == 0 && staged == 0) {
                minCommands++;
                staged = 1;
            }
        }
        printf("%d\n", minCommands);
    }
    return 0;
}

